from haystack import component

import tiktoken

@component
class TokenOverflowMonitor:
    @component.output_types(has_overflow=bool, token_count=int)
    def run(self, documents: list, query: str):
        encoder = tiktoken.encoding_for_model('gpt-4')
        context_tokens = sum(len(encoder.encode(doc.content)) for doc in documents)
        query_tokens = len(encoder.encode(query))
        total = context_tokens + query_tokens + 2000  # buffer for prompt
        return {'has_overflow': total > 128000, 'token_count': total}

